void rgbToComponents(int *d_r, int *d_g, int *d_b, unsigned char * h_src, int width, int height)
{
    int pixels      = width * height;
    int alignedSize =  divRndUp(width*height, THREADS) * THREADS * 3; 

	int *cl_d_src;
	cudaMalloc((void**)&cl_d_src, pixels*3);
	cudaMemcpy(cl_d_src, h_src, pixels*3, cudaMemcpyHostToDevice);

	size_t globalWorkSize = alignedSize/3;
    size_t localWorkSize = THREADS;

	c_CopySrcToComponents<<<globalWorkSize/localWorkSize, localWorkSize>>>(d_r, d_g, d_b, (unsigned char*)cl_d_src, pixels);
	cudaDeviceSynchronize();

	cudaFree(cl_d_src);
}






void bwToComponent(int *d_c, unsigned char * h_src, int width, int height)
{
    int pixels      = width*height;
    int alignedSize =  divRndUp(pixels, THREADS) * THREADS;

	unsigned char *cl_d_src;
	cudaMalloc((void**)&cl_d_src, pixels);
	cudaMemcpy(cl_d_src, h_src, pixels, cudaMemcpyHostToDevice);

	size_t globalWorkSize = alignedSize/9;
    size_t localWorkSize = THREADS;
	assert(alignedSize%(THREADS*3) == 0);

	c_CopySrcToComponent<<<globalWorkSize/localWorkSize, localWorkSize>>>(d_c, cl_d_src, pixels);
	cudaDeviceSynchronize();

	cudaFree(cl_d_src);
}











void launchFDWT53Kernel (int WIN_SX, int WIN_SY, int *in, int *out, int sx, int sy)
{




    const int steps = ( sy/ (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);	

	int gx = ( sx/ WIN_SX) + ((sx %  WIN_SX) ? 1 : 0);  
	int gy = ( sy/ (WIN_SY*steps)) + ((sy %  (WIN_SY*steps)) ? 1 : 0);

	printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);


	dim3 globalWorkSize(gx*WIN_SX, gy*1);
    dim3 localWorkSize(WIN_SX , 1);


	cl_fdwt53Kernel<<<globalWorkSize, localWorkSize>>>(in, out, sx, sy, steps, WIN_SX, WIN_SY);
	cudaDeviceSynchronize();

	printf("cl_fdwt53Kernel in launchFDW53Kernel has finished\n");


}








void memCopy (int *dest,  int *src, const size_t sx, const size_t sy){

	cudaMemcpy(dest, src, sx*sy*sizeof(int), cudaMemcpyDeviceToDevice);

}












void fdwt53(int *in, int *out, int sizeX, int sizeY, int levels)
{


    if(sizeX >= 960) 
	{
      launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    } 
	else if (sizeX >= 480) 
	{
      launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    } else 
	{
      launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);
	}


	if (levels > 1)
	{

		const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 :0);
		const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 :0);
		memCopy(in, out, llSizeX, llSizeY);


		fdwt53(in, out, llSizeX, llSizeY, levels - 1);
	}	
}




